// URL validation
function isSafeRedirect(url: string): boolean {
  try {
    const parsed = new URL(url, 'https://myapp.com');
    return parsed.origin === 'https://myapp.com'; // Only allow same-origin
  } catch { return false; }
}

// File upload validation
const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp'];
const MAX_SIZE = 5 * 1024 * 1024; // 5MB

function validateUpload(file: File): string | null {
  if (!ALLOWED_TYPES.includes(file.type)) return 'Invalid file type';
  if (file.size > MAX_SIZE) return 'File too large (max 5MB)';
  return null;
}

// Validate env at startup
import { z } from 'zod';

const envSchema = z.object({
  DATABASE_URL: z.string().url(),
  JWT_SECRET: z.string().min(32),
  FIREBASE_PROJECT_ID: z.string(),
  NEXT_PUBLIC_APP_URL: z.string().url(),
  // Optional with defaults
  PORT: z.coerce.number().default(3000),
  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
});

export const env = envSchema.parse(process.env);

